16.query:
fetch spans, scanLimitGBytes: 500

// filter for database spans
| filter span.kind == "client" and isNotNull(db.query.text)

// lookup service entity and use the service entity name as span attribute
| lookup [fetch dt.entity.service], sourceField: dt.entity.service, lookupField: id, fields: { service.name = entity.name }

// multiple database calls can be aggregated into one span
| fieldsAdd db_calls = coalesce(aggregation.count, 1)

| summarize { db_calls = sum(db_calls) }, by: { service.name, code.function, db.system, db.namespace, db.query.text }

// top list according to TopLimit variable
| sort db_calls desc | limit toLong($TopLimit)

17.query:
// Fetch entities in Databases app
data json: "[]"
| append [
    fetch `dt.entity.sql:postgres_instance`
    | fieldsAdd vendor_icon = "postgre"
]
| append [
    fetch `dt.entity.sql:sql_server_instance`
    | fieldsAdd vendor_icon = "sql-microsoft"
]
| filterOut isNull(id)
| fieldsKeep  vendor_icon
| dedup vendor_icon

//Joining with services using the supported vendor icon
| join [
    fetch dt.entity.service
    | filter serviceType == "DATABASE_SERVICE"
    | fields vendor_icon = icon[primaryIconType], databaseVendor
], on:{vendor_icon}, kind:inner, fields:{databaseVendor}
| summarize count(), by:{databaseVendor}

23.query:
fetch spans, samplingRatio: 1, scanLimitGBytes: 500

// based on the applied filters
| filter span.kind == "client" and isNotNull(db.query.text)

// calculate raw multiplicity based on sampling
| fieldsAdd multiplicity = coalesce(sampling.multiplicity, 1) * coalesce(aggregation.count, 1) * dt.system.sampling_ratio

// construct fields
| fieldsAdd span.status_code = if((span.status_code == "error" OR span.is_exit_by_exception), "Error", else: "Ok")

| makeTimeseries {
    avg = avg(duration),
    p50 = median(duration),
    p90 = percentile(duration, 90),
    p95 = percentile(duration, 95),
    p99 = percentile(duration, 99)
  }, bins: 120, by: { dt.system.sampling_ratio }

24.query:
fetch spans, samplingRatio: 1, scanLimitGBytes: 500

// based on the applied filters
| filter span.kind == "client" and isNotNull(db.query.text)
//| filter not(matchesValue(`db.query.text`, "null"))

// calculate raw multiplicity based on sampling
| fieldsAdd multiplicity = coalesce(sampling.multiplicity, 1) * coalesce(aggregation.count, 1) * dt.system.sampling_ratio

// construct fields
| fieldsAdd span.status_code = if((span.status_code == "error" OR span.is_exit_by_exception), "Error", else: "Ok")

// for multiplicity (due to sampling) sum() needs to be used instead of count()
| fieldsAdd failedIf = if(span.status_code == "Error", `multiplicity`, else: 0), successIf = if(span.status_code == "Ok", `multiplicity`, else: 0)

| makeTimeseries {
    failure = sum(failedIf, default: 0),
    success = sum(successIf, default: 0)
  }, bins: 120, by: { dt.system.sampling_ratio }
